VALUES
  ('cpa-moex-00368', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員認為受查者管理階層或治理單位成員疑似涉及未遵循法令事項時，下列何者非其所可採 取之行動？', '["與受查者更高層級或適當之權責單位（例如審計委員會或監察人）溝通", "依會計師職業道德規範要求，對該疑似涉及未遵循法令事項善盡保密義務，惟可向所屬會計師 公會報告", "依相關法令向適當之權責機關報告", "考量是否取得法律專家之意見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00369', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關採用查核人員專家之工作作為查核證據之考量，下列敘述何者錯誤？', '["儘管會計師得採用查核人員專家之發現或結論作為適切之查核證據，但其責任不因採用專家之 工作而減輕", "儘管查核人員在會計或審計以外之某一領域非屬專家，仍可能在無專家協助之情況下執行查核 工作", "儘管會計師得採用查核人員專家工作作為查核證據，但仍應取得對查核人員專家專門知識領域 之瞭解", "會計師得於無保留意見之查核報告中提及查核人員專家之工作，以便讓查核報告使用者瞭解其 查核結論的基礎"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00370', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員應瞭解與查核攸關之內部控制，且應對受查者控制作業與如何因應資訊科技所產生之風 險加以瞭解。下列敘述何者錯誤？', '["資訊科技對受查者之內部控制，通常具有增加資訊之及時性、可取得性與正確性等優點", "受查者內部控制中人工作業及自動化作業之運用，因受查者使用資訊科技之性質及複雜程度而 有所不同", "航空公司維護航班表所使用之自動化控制系統，因該等控制系統通常與查核無關，故無須納入 查核之考量", "依人力資源政策及實務之要求，聘僱具專業能力之財務會計及資訊科技人員，可減少處理財務 資訊發生錯誤之風險，並有效抑制高階管理階層高估盈餘之強烈傾向"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00371', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關查核規劃之規定，下列敘述何者正確？', '["查核規劃由主辦會計師獨自完成", "查核策略應較查核計畫更為詳細", "查核人員應將查核策略與查核計畫作成書面紀錄", "查核規劃的目的，因查核案件為首次受託或續任而有所不同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00372', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '受查者將龐大的賒銷客戶之授信資料及交易情形均納入電腦處理及儲存，查核人員為評估備抵壞 帳是否適當，擬查核其超額賒銷之違規情形，下列何者是最有效果的查核程序？', '["以測試資料（testdata）將超限交易輸入，以此測試相關程式控制之可靠程度", "以電腦查核程式將授信額度與帳款餘額逐筆比較，並列印超限情形", "請客戶提供應收帳款明細及信用額度明細，以利人工親自審核", "抽查部分帳款餘額，比較其信用額度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00373', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列何者通常不會納入查核報告中之強調事項段？', '["重大期後事項", "重大關係人交易", "重大訴訟或監管措施未來結果之不確定性", "前一年度財務報表係由其他會計師查核"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00374', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關查核報告中關鍵查核事項之說明，下列何者正確？', '["一份查核報告只能有一個關鍵查核事項", "會計師溝通關鍵查核事項代表其對於該項目單獨表示意見", "關鍵查核事項為會計師與治理單位溝通的事項中，對本期財務報表之查核最為重要之事項", "關鍵查核事項為依會計師之判斷，須作特殊查核考量之所有已辨認及已評估具有重大不實表達 風險之事項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00375', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列有關依照允當表達架構所編製之財務報表審計之敘述，何者正確？①審計工作必須周密妥', '["所適用之財務報導架構可以作為判斷財 務報表是否允當表達之衡量基準", "財務報表經由獨立會計師審計驗證後，其內容絕對正確可靠", "經審計之財務報表資訊較具公信力與允當性，對財報使用者更具效用", "僅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00376', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列那一種廣告宣傳可能使會計師違反職業道德規範？', '["刊登招募助理人員之廣告", "刊登稅務訓練課程之招生廣告", "刊登事務所變更組織形式之廣告", "刊登祝賀所簽證公司成功上市之廣告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00377', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '質性因素可能影響查核人員對重大性的評估，下列那一項相關之敘述是錯誤的？', '["假如不實表達在金額上不具重大性，但會產生契約的義務，則可能被認為是重大的", "假如不實表達在金額上不具重大性，但會影響財務報表使用者對收益趨勢的認知，則可能被認 為是重大的", "管理階層從事的財務報表舞弊，仍應依其舞弊金額的大小，判斷是否具有重大性", "管理階層及員工從事的舞弊，通常被認為具有不同的重大性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00378', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列那一項最不可能是查核人員執行風險評估程序所用之查核方法？', '["外部函證", "分析性程序", "觀察及檢查", "查詢"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00379', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員對受查者內部控制制度那兩項組成要素之瞭解，較可能影響個別項目聲明重大不實表達 風險之辨認及評估？', '["資訊系統及溝通與控制作業", "控制環境與控制作業", "受查者監督內部控制制度之流程與受查者之風險評估流程", "受查者之風險評估流程與控制作業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00380', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列那一種情況，查核人員最不適合採用以往控制測試所取得之查核證據？', '["受查者之資訊系統一般控制係屬有效", "受查者當年度管理資訊系統進行更新", "與該控制相關之重大不實表達風險較低", "受查者與財務報導相關之內部稽核職能運作良好"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00381', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列何種現象最可能被查核人員認為受查者存有財務報表不實表達之風險？', '["受查者所屬產業競爭程度低，受查者淨利上升", "管理階層於財務報告中揭露企業存有未決訴訟並認列負債準備", "受查者交易高度依賴電腦化處理，缺乏書面審計軌跡", "期末調整分錄金額重大，且對本期獲利產生重大影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00382', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員瞭解並評估受查者之內部控制時，下列敘述何者錯誤？', '["查核人員取得對受查者控制設計並付諸實行之瞭解後，無法證明該控制執行有效", "對於實施自動化作業之受查者，查核人員透過執行確認自動化控制是否已付諸實行之程序，即 可作為控制執行有效之證據", "查核人員應瞭解所有與查核攸關之控制作業，以評估個別項目聲明之重大不實表達風險，及因 應所評估風險而設計進一步查核程序", "無論內部控制之有效程度為何，都僅能對受查者財務報導目標之達成提供合理之確信"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00383', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '如受查者與供應商之交易條件被要求由信用交易改為預付現金交易，查核人員辨認為繼續經營能 力可能產生重大疑慮之事件，為取得足夠及適切之查核證據以確認是否存在重大不確定性，查核 人員應執行之額外查核程序不包括下列何者？', '["要求管理階層對企業繼續經營之能力執行評估，考量管理階層作出評估後，有無可取得之額外 事實或資訊", "評估管理階層之未來因應計畫，以判斷管理階層執行該因應計畫之結果是否可改善現狀，以及 該因應計畫於當時情況下是否可行", "評估管理階層據以編製現金流量預測之資料是否可靠，並判斷與預測相關之假設是否有足夠之 佐證", "判斷財務報表是否適當揭露使企業繼續經營之能力可能產生重大疑慮之主要事件或情況，以及 管理階層之因應計畫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00384', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員於最後評估是否已獲得足夠與適切查核證據階段時，較不可能進行下列何項程序？', '["複核整個查核工作中的查核工作底稿，以判斷是否所有重大交易類別均已執行適當之查核測試 程序", "確保查核計畫的所有部分均已適當完成且記錄於工作底稿中", "確認查核團隊所有成員之獨立性", "判斷查核計畫是否適當"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL);
